// ===========================================================================
// Sanity test: every fixture file is loadable + decodable. Doesn't require
// a running server, so it stays out of `#[ignore]` — runs in `cargo test`.
// ===========================================================================

#[test]
fn fixtures_are_loadable() -> Result<()> {
    let trace_fixtures = [
        "guardrails_input_halt",
        "guardrails_action_passthrough",
        "nat_simple_workflow",
        "nat_multi_function",
        "openinference_langchain",
    ];
    for name in trace_fixtures {
        let (bytes, meta) = load_fixture(name)?;
        let req = ExportTraceServiceRequest::decode(bytes.as_slice())
            .with_context(|| format!("decode {name}.binpb"))?;
        assert!(
            !req.resource_spans.is_empty(),
            "{name}: empty resource_spans"
        );
        assert_eq!(
            meta.get("fixture").and_then(|v| v.as_str()),
            Some(name),
            "{name}: meta.fixture field mismatch"
        );
        assert_eq!(meta.get("kind").and_then(|v| v.as_str()), Some("traces"));
    }

    let (bytes, meta) = load_fixture("evaluator_score")?;
    let req = ExportLogsServiceRequest::decode(bytes.as_slice())?;
    assert!(!req.resource_logs.is_empty());
    assert_eq!(meta.get("kind").and_then(|v| v.as_str()), Some("logs"));
    Ok(())
}
